import React, { useState, useEffect } from 'react';
import { 
  Paper, 
  BottomNavigation as MuiBottomNavigation, 
  BottomNavigationAction,
  Box,
  Badge,
  useMediaQuery
} from '@mui/material';
import { styled, alpha, useTheme } from '@mui/material/styles';
import { 
  Home, 
  Person, 
  DirectionsCar,
  Notifications,
  AccountBalanceWallet
} from '@mui/icons-material';
import { useLocation, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useNotifications } from '../../hooks/useNotifications';

// Объявляем расширенный интерфейс Window для типизации Telegram WebApp
declare global {
  interface Window {
    Telegram?: {
      WebApp?: {
        BackButton?: {
          isVisible: boolean;
          show: () => void;
          hide: () => void;
          onClick: (callback: () => void) => void;
        }
        MainButton?: {
          text: string;
          color: string;
          textColor: string;
          isVisible: boolean;
          isActive: boolean;
          show: () => void;
          hide: () => void;
          enable: () => void;
          disable: () => void;
          onClick: (callback: () => void) => void;
        }
        setHeaderColor: (color: string) => void;
        ready: () => void;
        expand: () => void;
      };
    };
  }
}

const StyledBottomNavigation = styled(Paper)(({ theme }) => ({
  position: 'fixed',
  bottom: 0,
  left: 0,
  right: 0,
  zIndex: 100,
  borderTopLeftRadius: 24,
  borderTopRightRadius: 24,
  overflow: 'hidden',
  boxShadow: '0 -4px 20px rgba(0,0,0,0.08)',
  backgroundColor: theme.palette.mode === 'light' 
    ? alpha(theme.palette.background.paper, 0.98)
    : alpha(theme.palette.background.paper, 0.95),
  backdropFilter: 'blur(15px)',
  borderTop: `1px solid ${alpha(theme.palette.divider, 0.08)}`,
  height: 72,
  width: '100%',
  maxWidth: 540,
  margin: '0 auto',
  paddingBottom: 'env(safe-area-inset-bottom)',
}));

const AnimatedNavAction = styled(motion.div)({
  flex: 1,
  display: 'flex',
  justifyContent: 'center',
  position: 'relative',
});

const NavIndicator = styled(motion.div)(({ theme }) => ({
  width: 5,
  height: 5,
  borderRadius: '50%',
  backgroundColor: theme.palette.primary.main,
  position: 'absolute',
  bottom: 6,
  boxShadow: `0 0 10px ${theme.palette.primary.main}`,
}));

const StyledBottomNavigationAction = styled(BottomNavigationAction)(({ theme }) => ({
  minWidth: 'auto',
  padding: '8px 0',
  '&.Mui-selected': {
    paddingTop: 6,
    '& .MuiBottomNavigationAction-label': {
      fontWeight: 700,
      fontSize: '0.78rem',
      transform: 'none',
      visibility: 'visible',
    },
    '& .MuiSvgIcon-root': {
      color: theme.palette.primary.main,
      transform: 'translateY(-4px) scale(1.1)',
    },
  },
  '& .MuiBottomNavigationAction-label': {
    fontSize: '0.75rem',
    fontWeight: 500,
    transition: 'all 0.2s ease',
    marginTop: 4,
  },
  '& .MuiSvgIcon-root': {
    fontSize: '1.8rem',
    transition: 'all 0.2s ease',
  },
}));

interface BottomNavigationBarProps {}

const BottomNavigationBar: React.FC<BottomNavigationBarProps> = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const theme = useTheme();
  const { unreadCount } = useNotifications();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));
  const currentPath = location.pathname.split('/')[1] || '/';
  const [mounted, setMounted] = useState(false);
  
  // Определяем, находимся ли мы в Telegram Mini App
  const [isTelegramMiniApp, setIsTelegramMiniApp] = useState(false);
  
  useEffect(() => {
    // Проверка на Telegram Mini App через window.Telegram
    try {
      const isTelegram = Boolean(window.Telegram?.WebApp);
      setIsTelegramMiniApp(isTelegram);
    } catch (e) {
      setIsTelegramMiniApp(false);
    }
    
    setMounted(true);
  }, []);
  
  const handleChange = (event: React.SyntheticEvent<Element, Event>, newValue: string) => {
    // Добавляем визуальный эффект нажатия перед навигацией
    const target = event.currentTarget as HTMLElement;
    if (target) {
      target.style.transform = 'scale(0.95)';
      setTimeout(() => {
        target.style.transform = 'scale(1)';
        navigate(newValue);
      }, 100);
    } else {
      navigate(newValue);
    }
  };
  
  // Функция обработки клика для каждой кнопки навигации
  const handleNavClick = (path: string) => (event: React.MouseEvent) => {
    const target = event.currentTarget as HTMLElement;
    if (target) {
      target.style.transform = 'scale(0.95)';
      setTimeout(() => {
        target.style.transform = 'scale(1)';
        navigate(path);
      }, 100);
    }
  };
  
  if (!mounted) return null;
  
  return (
    <StyledBottomNavigation
      elevation={0}
      className="safe-area-padding-bottom"
      sx={{ 
        height: isTelegramMiniApp ? 80 : 72,
        display: 'block', 
        position: 'fixed',
        bottom: 0,
        left: 0,
        right: 0,
        zIndex: 1000,
      }}
    >
      <MuiBottomNavigation
        value={currentPath === '/' ? '/' : `/${currentPath}`}
        onChange={handleChange}
        sx={{
          height: '100%',
          justifyContent: 'space-around',
          px: 2,
        }}
      >
        <AnimatedNavAction onClick={handleNavClick('/')}>
          <StyledBottomNavigationAction 
            label="Главная" 
            value="/" 
            icon={<Home fontSize="medium" />} 
          />
          {currentPath === '/' && <NavIndicator layoutId="navIndicator" />}
        </AnimatedNavAction>
        
        <AnimatedNavAction onClick={handleNavClick('/raffles')}>
          <StyledBottomNavigationAction 
            label="Розыгрыши" 
            value="/raffles" 
            icon={<DirectionsCar fontSize="medium" />} 
          />
          {currentPath === 'raffles' && <NavIndicator layoutId="navIndicator" />}
        </AnimatedNavAction>
        
        <AnimatedNavAction onClick={handleNavClick('/wallet')}>
          <StyledBottomNavigationAction 
            label="Кошелек" 
            value="/wallet" 
            icon={<AccountBalanceWallet fontSize="medium" />} 
          />
          {currentPath === 'wallet' && <NavIndicator layoutId="navIndicator" />}
        </AnimatedNavAction>
        
        <AnimatedNavAction onClick={handleNavClick('/notifications')}>
          <StyledBottomNavigationAction 
            label="Уведомления" 
            value="/notifications" 
            icon={
              <Badge 
                color="error" 
                variant="dot" 
                invisible={unreadCount === 0}
                sx={{ 
                  '& .MuiBadge-badge': {
                    top: 0,
                    right: 0,
                    boxShadow: `0 0 0 2px ${theme.palette.background.paper}`
                  }
                }}
              >
                <Notifications fontSize="medium" />
              </Badge>
            } 
          />
          {currentPath === 'notifications' && <NavIndicator layoutId="navIndicator" />}
        </AnimatedNavAction>
        
        <AnimatedNavAction onClick={handleNavClick('/profile')}>
          <StyledBottomNavigationAction 
            label="Профиль" 
            value="/profile" 
            icon={<Person fontSize="medium" />} 
          />
          {currentPath === 'profile' && <NavIndicator layoutId="navIndicator" />}
        </AnimatedNavAction>
      </MuiBottomNavigation>
    </StyledBottomNavigation>
  );
};

export default BottomNavigationBar;
